B.akk=new A.kz("1. Data Storage",null)
B.ai1=new A.jO("All data you enter \u2014 including health records, lab results, diagnoses, fitness logs, sleep data, nutrition, supplements, symptoms, mood, genomics, and any other personal health information \u2014 is stored exclusively on your device using a local SQLite database. No data is uploaded to any server operated by HealthVault.",null)
